import type { QAItem } from '../interview-data'

export const REACT_NEXTJS_DATA: QAItem[] = [
  // === React - JSX & Cơ Bản (401-415) ===
  { id: 401, category: "React", subcategory: "JSX & Cơ Bản", level: "beginner", q: "JSX là gì và tại sao React sử dụng nó?", a: "JSX (JavaScript XML) là cú pháp mở rộng của JavaScript cho phép viết HTML bên trong JavaScript. React sử dụng JSX vì nó giúp mô tả UI trực quan hơn, kết hợp logic và markup trong cùng một file component. Babel transpile JSX thành các lời gọi React.createElement() trước khi chạy trên trình duyệt." },
  { id: 402, category: "React", subcategory: "JSX & Cơ Bản", level: "beginner", q: "JSX được transpile thành gì? Hãy cho ví dụ minh họa.", a: "JSX được Babel transpile thành React.createElement(type, props, ...children). Ví dụ: `<h1 className='title'>Hello</h1>` trở thành `React.createElement('h1', { className: 'title' }, 'Hello')`. Kể từ React 17, có thể sử dụng JSX mà không cần import React nhờ transform tự động." },
  { id: 403, category: "React", subcategory: "JSX & Cơ Bản", level: "beginner", q: "Conditional rendering trong React được thực hiện như thế nào?", a: "Có nhiều cách: dùng toán tử ba ngôi (ternary) `condition ? <A /> : <B />`, dùng toán tử && `condition && <Component />`, hoặc dùng if/else bên ngoài return. Toán tử && cần lưu ý tránh render số 0 khi điều kiện là falsy number." },
  { id: 404, category: "React", subcategory: "JSX & Cơ Bản", level: "beginner", q: "React Fragment là gì và khi nào nên sử dụng?", a: "React Fragment (`<React.Fragment>` hoặc `<>`) cho phép nhóm nhiều phần tử mà không thêm node DOM thừa. Sử dụng khi component cần trả về nhiều phần tử cùng cấp, ví dụ trong table rows hay danh sách. Cú pháp rút gọn `<>...</>` không hỗ trợ thuộc tính key, cần dùng `<React.Fragment key={id}>` khi render danh sách." },
  { id: 405, category: "React", subcategory: "JSX & Cơ Bản", level: "beginner", q: "Key prop trong React là gì và tại sao nó quan trọng?", a: "Key là prop đặc biệt giúp React xác định phần tử nào trong danh sách đã thay đổi, được thêm hoặc bị xóa. React sử dụng key để tối ưu hóa quá trình reconciliation, tránh re-render không cần thiết. Key phải là chuỗi hoặc số duy nhất trong cùng cấp độ, không nên dùng index khi danh sách có thể thay đổi thứ tự." },
  { id: 406, category: "React", subcategory: "JSX & Cơ Bản", level: "beginner", q: "Tại sao phải dùng className thay vì class trong JSX?", a: "JSX được biên dịch thành JavaScript, và class là từ khóa dành riêng trong JavaScript (dùng để khai báo lớp). Do đó React sử dụng className để ánh xạ đến thuộc tính class của DOM. Tương tự, for của label được thay bằng htmlFor trong JSX." },
  { id: 407, category: "React", subcategory: "JSX & Cơ Bản", level: "beginner", q: "Làm thế nào để render danh sách trong JSX?", a: "Dùng Array.map() để chuyển đổi mảng dữ liệu thành mảng JSX elements. Mỗi phần tử cần có thuộc tính key duy nhất để React theo dõi. Ví dụ: `{items.map(item => <li key={item.id}>{item.name}</li>)}`. Tránh dùng index làm key nếu thứ tự danh sách có thể thay đổi." },
  { id: 408, category: "React", subcategory: "JSX & Cơ Bản", level: "beginner", q: "Sự khác nhau giữa biểu thức và câu lệnh trong JSX là gì?", a: "JSX chỉ chấp nhận biểu thức (expressions) bên trong dấu ngoặc nhọn {}, không chấp nhận câu lệnh (statements) như if, for, while. Để dùng điều kiện, sử dụng toán tử ternary hoặc &&. Để lặp, dùng map(), filter() thay vì vòng lặp for thông thường." },
  { id: 409, category: "React", subcategory: "JSX & Cơ Bản", level: "intermediate", q: "Inline styles trong JSX hoạt động như thế nào?", a: "Trong JSX, inline style nhận vào một object JavaScript với camelCase property thay vì kebab-case CSS. Ví dụ: `style={{ backgroundColor: 'red', fontSize: '16px' }}`. Giá trị số tự động được thêm đơn vị px, nhưng một số thuộc tính như zIndex, opacity nhận số thuần. Double braces là do brace ngoài là JSX expression, brace trong là object." },
  { id: 410, category: "React", subcategory: "JSX & Cơ Bản", level: "beginner", q: "Event handling trong JSX khác gì so với HTML thông thường?", a: "Trong JSX, tên event dùng camelCase (onClick, onChange, onSubmit) thay vì lowercase. Handler là function reference, không phải string. Để ngăn hành vi mặc định, gọi e.preventDefault() trong handler thay vì return false. React sử dụng synthetic events để đảm bảo tính nhất quán giữa các trình duyệt." },
  { id: 411, category: "React", subcategory: "JSX & Cơ Bản", level: "intermediate", q: "Self-closing tags trong JSX được dùng như thế nào?", a: "Mọi JSX element đều phải được đóng, kể cả các thẻ HTML tự đóng. Các thẻ không có con có thể dùng self-closing syntax: `<br />`, `<img />`, `<MyComponent />`. Đây là yêu cầu bắt buộc khác với HTML5 nơi `<br>` và `<img>` không cần đóng." },
  { id: 412, category: "React", subcategory: "JSX & Cơ Bản", level: "beginner", q: "Spread operator trong JSX props được dùng như thế nào?", a: "Dùng `{...props}` để truyền tất cả thuộc tính của một object xuống component con. Ví dụ: `<Button {...buttonProps} />` tương đương với liệt kê từng prop riêng lẻ. Hữu ích khi cần forward props nhưng cần cẩn thận vì có thể truyền props không mong muốn." },
  { id: 413, category: "React", subcategory: "JSX & Cơ Bản", level: "intermediate", q: "JSX có hỗ trợ comment không? Cú pháp như thế nào?", a: "JSX hỗ trợ comment bên trong expression: `{/* Comment JSX */}`. Comment JavaScript thông thường (// hoặc /* */) không thể dùng trực tiếp bên trong JSX markup. Comment đặt ở cấp độ attribute: `{/* comment */}` hoặc trên một dòng riêng trong JSX." },
  { id: 414, category: "React", subcategory: "JSX & Cơ Bản", level: "beginner", q: "Sự khác biệt giữa null, undefined, false và chuỗi rỗng khi render trong JSX là gì?", a: "React không render null, undefined, false - chúng trả về element rỗng (hữu ích cho conditional rendering). Chuỗi rỗng '' vẫn không render gì hiển thị. Tuy nhiên số 0 sẽ được render ra màn hình, đây là lỗi hay gặp khi dùng `count && <Component />`." },
  { id: 415, category: "React", subcategory: "JSX & Cơ Bản", level: "intermediate", q: "Tại sao mỗi component React chỉ có thể return một element duy nhất ở cấp cao nhất?", a: "Vì JSX được transpile thành một lời gọi hàm React.createElement() đơn, và hàm chỉ có thể return một giá trị. Để return nhiều element, dùng Fragment (`<>...</>`) hoặc bọc trong một wrapper element như `<div>`. Fragment là lựa chọn tốt hơn vì không thêm node DOM không cần thiết." },

  // === React - Components (416-430) ===
  { id: 416, category: "React", subcategory: "Components", level: "beginner", q: "Sự khác nhau giữa Function Component và Class Component là gì?", a: "Function Component là hàm JavaScript trả về JSX, đơn giản và ngắn gọn hơn. Class Component kế thừa từ React.Component, có lifecycle methods và this context. Kể từ React 16.8 với Hooks, Function Component có thể làm mọi thứ Class Component làm được và được khuyến khích sử dụng. Class Component vẫn tồn tại nhưng không còn được khuyến nghị cho code mới." },
  { id: 417, category: "React", subcategory: "Components", level: "beginner", q: "props.children là gì và cách sử dụng như thế nào?", a: "props.children là nội dung được truyền giữa thẻ mở và đóng của component. Ví dụ: `<Card><p>Content</p></Card>` thì Card nhận `<p>Content</p>` qua props.children. Cho phép tạo component wrapper linh hoạt như Card, Modal, Layout mà không cần biết trước nội dung bên trong." },
  { id: 418, category: "React", subcategory: "Components", level: "beginner", q: "Default props trong React được khai báo như thế nào?", a: "Trong Function Component, dùng default parameter: `function Button({ color = 'blue', size = 'md' }) {}`. Trong Class Component, khai báo `ComponentName.defaultProps = { color: 'blue' }` ngoài class. Có thể dùng TypeScript để định nghĩa props type kết hợp với default values." },
  { id: 419, category: "React", subcategory: "Components", level: "intermediate", q: "Pure Component là gì và nó khác gì Component thông thường?", a: "Pure Component trong Class Component là React.PureComponent, tự động implement shouldComponentUpdate với shallow comparison của props và state. Trong Function Component, tương đương là React.memo() wrap component. Hữu ích để tránh re-render không cần thiết khi props không thay đổi. Shallow comparison có thể bỏ qua thay đổi của nested objects." },
  { id: 420, category: "React", subcategory: "Components", level: "beginner", q: "Controlled Component là gì trong React?", a: "Controlled Component là component mà giá trị của form element (input, textarea, select) được kiểm soát bởi React state. Mỗi thay đổi của input gọi onChange handler để cập nhật state, và value của input được bind với state. Đây là cách được khuyến nghị vì cho phép validate và xử lý dữ liệu trước khi submit." },
  { id: 421, category: "React", subcategory: "Components", level: "intermediate", q: "Component composition là gì và tại sao nên dùng thay vì inheritance?", a: "Composition là kỹ thuật xây dựng component phức tạp từ các component đơn giản hơn thay vì kế thừa. React khuyến khích composition vì nó linh hoạt hơn, dễ test hơn và tránh các vấn đề của prototype chain. Patterns như children prop, render props, và slots đều là biểu hiện của composition." },
  { id: 422, category: "React", subcategory: "Components", level: "beginner", q: "Tên component React phải bắt đầu bằng chữ hoa. Tại sao vậy?", a: "React dùng quy ước này để phân biệt DOM elements (lowercase) với React components (uppercase). `<div>` được render như HTML element, `<Button>` được render như custom React component. Nếu component bắt đầu bằng chữ thường, React sẽ coi đó là DOM element và tìm kiếm trong HTML spec." },
  { id: 423, category: "React", subcategory: "Components", level: "intermediate", q: "Displayname trong React component dùng để làm gì?", a: "displayName là thuộc tính string dùng để đặt tên cho component, hữu ích khi debug với React DevTools. Mặc định React lấy tên hàm, nhưng với HOC hay anonymous function, displayName giúp xác định component dễ hơn. Ví dụ: `withAuth.displayName = 'withAuth(Component)'`." },
  { id: 424, category: "React", subcategory: "Components", level: "intermediate", q: "Sự khác nhau giữa React.Component và React.PureComponent là gì?", a: "React.Component không có bất kỳ tối ưu hóa re-render nào mặc định. React.PureComponent tự động implement shouldComponentUpdate với shallow comparison props và state, ngăn re-render khi props/state không thay đổi. Tuy nhiên, PureComponent có thể bỏ sót update nếu dùng mutate thay vì immutable update." },
  { id: 425, category: "React", subcategory: "Components", level: "advanced", q: "Forwardref trong React là gì và khi nào cần dùng?", a: "React.forwardRef cho phép component nhận ref từ parent và forward xuống DOM element hoặc component con bên trong. Cần thiết khi muốn parent có thể trực tiếp access DOM node của child, ví dụ để focus input hay measure element. Cú pháp: `const Input = React.forwardRef((props, ref) => <input ref={ref} {...props} />)`." },
  { id: 426, category: "React", subcategory: "Components", level: "beginner", q: "Stateless và stateful component khác nhau như thế nào?", a: "Stateless (presentational) component chỉ nhận props và render UI, không có state nội bộ, dễ test và tái sử dụng. Stateful (container) component quản lý state và business logic, thường kết nối với data layer. Sự phân biệt này giờ ít rõ ràng hơn vì Hooks cho phép function component có state." },
  { id: 427, category: "React", subcategory: "Components", level: "intermediate", q: "Compound Components pattern là gì?", a: "Compound Components là pattern cho phép các component liên quan chia sẻ state ngầm qua Context. Ví dụ: `<Select>`, `<Select.Option>` chia sẻ state selected value mà không cần props drilling. Pattern này tạo API linh hoạt, cho phép user sắp xếp sub-components theo ý muốn trong khi vẫn duy trì shared state." },
  { id: 428, category: "React", subcategory: "Components", level: "intermediate", q: "Sự khác biệt giữa mount, update và unmount trong vòng đời component là gì?", a: "Mount là khi component được thêm vào DOM lần đầu tiên. Update xảy ra khi props hoặc state thay đổi, khiến component re-render. Unmount là khi component bị xóa khỏi DOM. Các lifecycle methods (componentDidMount, componentDidUpdate, componentWillUnmount) hoặc useEffect hook xử lý các giai đoạn này." },
  { id: 429, category: "React", subcategory: "Components", level: "advanced", q: "Component colocation là gì và tại sao nó được khuyến nghị?", a: "Colocation là nguyên tắc đặt code gần nơi nó được sử dụng nhất - state, event handlers, styles của component nên nằm trong cùng file hoặc thư mục. Giúp code dễ hiểu và maintain hơn, giảm cognitive load khi chỉnh sửa một feature. Ví dụ: đặt query data fetching trong component cần dữ liệu thay vì ở global store." },
  { id: 430, category: "React", subcategory: "Components", level: "beginner", q: "React component có thể return gì ngoài JSX?", a: "Component có thể return: JSX element, null (không render gì), array of elements, string, number, Portal, Fragment. Return null hữu ích để ẩn component mà không thay đổi cấu trúc. Array cần có key cho mỗi element. String và number được render trực tiếp như text node." },

  // === React - Props & State (431-445) ===
  { id: 431, category: "React", subcategory: "Props & State", level: "beginner", q: "Sự khác nhau cơ bản giữa props và state trong React là gì?", a: "Props là dữ liệu được truyền từ component cha xuống con, read-only và không thể thay đổi bởi component nhận. State là dữ liệu nội bộ của component, có thể thay đổi theo thời gian và kích hoạt re-render. Props giống như tham số hàm, state giống như biến cục bộ của component." },
  { id: 432, category: "React", subcategory: "Props & State", level: "intermediate", q: "Lifting state up là gì và khi nào cần thực hiện?", a: "Lifting state up là kỹ thuật di chuyển state lên component cha chung gần nhất khi nhiều component cần chia sẻ cùng dữ liệu. Cha sẽ pass state xuống con qua props và pass callback để con có thể cập nhật state. Cần làm khi hai sibling components cần đồng bộ dữ liệu." },
  { id: 433, category: "React", subcategory: "Props & State", level: "beginner", q: "setState trong Class Component hoạt động như thế nào?", a: "setState() không cập nhật state ngay lập tức mà queue update và React có thể batch nhiều setState lại. Tham số có thể là object mới hoặc updater function `(prevState) => newState`. Dùng updater function khi cần dựa vào giá trị state hiện tại để tránh race condition." },
  { id: 434, category: "React", subcategory: "Props & State", level: "intermediate", q: "Immutability trong React state là gì và tại sao quan trọng?", a: "Immutability nghĩa là không trực tiếp mutate state mà tạo object/array mới. React dùng shallow comparison để detect thay đổi, nếu mutate trực tiếp React sẽ không nhận ra sự thay đổi và không re-render. Dùng spread operator `{...state, field: value}` hoặc Array.map/filter để tạo bản sao mới." },
  { id: 435, category: "React", subcategory: "Props & State", level: "intermediate", q: "Làm thế nào để cập nhật nested state objects một cách đúng đắn?", a: "Dùng spread operator để tạo bản sao ở mỗi cấp: `setState(prev => ({ ...prev, user: { ...prev.user, name: 'new' } }))`. Với nested sâu, xem xét dùng Immer library cho phép viết code mutate nhưng tạo immutable update dưới hood. Cấu trúc state phẳng (flat) cũng giúp tránh vấn đề này." },
  { id: 436, category: "React", subcategory: "Props & State", level: "beginner", q: "Khi nào nên dùng props và khi nào nên dùng state?", a: "Dùng state cho dữ liệu thay đổi theo tương tác của người dùng hoặc theo thời gian (form values, toggle, data từ API). Dùng props để truyền dữ liệu và callbacks từ cha xuống con. Nếu dữ liệu không thay đổi và chỉ đọc từ ngoài, đó là props. Nếu component tự quản lý, đó là state." },
  { id: 437, category: "React", subcategory: "Props & State", level: "intermediate", q: "Derived state là gì và những vấn đề thường gặp?", a: "Derived state là state được tính toán từ props. Vấn đề: khi dùng getDerivedStateFromProps sai cách, component có thể mất state khi props thay đổi. React khuyến nghị: tính toán giá trị derived trong render thay vì lưu vào state, hoặc dùng fully controlled/uncontrolled với key prop để reset. Tránh anti-pattern copy props vào state." },
  { id: 438, category: "React", subcategory: "Props & State", level: "advanced", q: "State batching trong React là gì? Thay đổi trong React 18?", a: "State batching là React gộp nhiều setState calls lại và chỉ re-render một lần. Trong React 17, chỉ batch trong event handlers. React 18 giới thiệu Automatic Batching, batch cả trong setTimeout, Promise, và native event handlers. Dùng `flushSync()` để opt-out batching khi cần update ngay lập tức." },
  { id: 439, category: "React", subcategory: "Props & State", level: "beginner", q: "Tại sao không nên trực tiếp mutate state trong React?", a: "Mutating state trực tiếp không trigger re-render vì React compare object references, không phải deep values. Điều này gây ra bugs khó debug khi UI không cập nhật dù data đã thay đổi. Luôn tạo object/array mới khi cập nhật state: `setState([...prevArr, newItem])` thay vì `arr.push(newItem); setState(arr)`." },
  { id: 440, category: "React", subcategory: "Props & State", level: "intermediate", q: "Unidirectional data flow trong React nghĩa là gì?", a: "Dữ liệu trong React chỉ chảy một chiều từ cha xuống con qua props. Con không thể trực tiếp thay đổi state của cha mà phải thông qua callback function được truyền xuống. Pattern này giúp code dễ predict, trace bug dễ hơn và tránh side effects không mong muốn." },
  { id: 441, category: "React", subcategory: "Props & State", level: "advanced", q: "Khi nào state update là synchronous, khi nào là asynchronous?", a: "State updates luôn được schedule (không thực sự async/sync), React quyết định khi nào flush updates. Trong React 18 với automatic batching, hầu hết updates được defer. Dùng `flushSync()` để force synchronous update. Trong useEffect và event handlers nên luôn sử dụng functional updater form để tránh stale closure." },
  { id: 442, category: "React", subcategory: "Props & State", level: "beginner", q: "PropTypes là gì và cách sử dụng trong React?", a: "PropTypes là thư viện riêng (`prop-types` package, tách khỏi React core từ v15.5) để validate kiểu dữ liệu của props runtime. Định nghĩa: `Component.propTypes = { name: PropTypes.string.isRequired }`. Hiện nay TypeScript được ưa chuộng hơn vì kiểm tra compile-time, nhưng PropTypes vẫn hữu ích trong project JS. React sẽ warn trong console development khi prop không đúng kiểu." },
  { id: 443, category: "React", subcategory: "Props & State", level: "intermediate", q: "Làm thế nào để chia sẻ state giữa các component không có quan hệ cha-con?", a: "Các cách: dùng Context API để chia sẻ state ở global scope, dùng state management library (Redux, Zustand, Jotai), hoặc lifting state up đến ancestor chung rồi pass xuống qua props. Với component xa nhau trong tree, Context hoặc state management library là giải pháp tốt nhất." },
  { id: 444, category: "React", subcategory: "Props & State", level: "intermediate", q: "Controlled vs Uncontrolled components khác nhau như thế nào?", a: "Controlled component: giá trị form được kiểm soát bởi React state, phải có onChange handler, phù hợp khi cần validation hay transform dữ liệu. Uncontrolled component: giá trị lưu trong DOM, dùng ref để đọc, đơn giản hơn cho form không cần real-time validation. React khuyến nghị Controlled trong hầu hết trường hợp." },
  { id: 445, category: "React", subcategory: "Props & State", level: "advanced", q: "Tại sao không nên khởi tạo state từ props trực tiếp?", a: "Khởi tạo state từ props (`useState(props.value)`) chỉ chạy một lần khi mount, khi props thay đổi state sẽ không cập nhật theo. Đây là anti-pattern gây ra bugs khó phát hiện. Nếu cần derived state từ props, hoặc tính toán trong render, hoặc dùng useEffect để sync, hoặc làm component fully controlled." },

  // === React - Lifecycle (446-455) ===
  { id: 446, category: "React", subcategory: "Lifecycle", level: "beginner", q: "componentDidMount được gọi khi nào và dùng để làm gì?", a: "componentDidMount được gọi ngay sau khi component được mount vào DOM lần đầu tiên. Đây là nơi phù hợp để: fetch dữ liệu từ API, subscribe event listeners, khởi tạo thư viện bên thứ ba cần DOM (như charts). Tương đương với `useEffect(() => {}, [])` trong function component." },
  { id: 447, category: "React", subcategory: "Lifecycle", level: "intermediate", q: "componentDidUpdate hoạt động như thế nào và khi nào nên dùng?", a: "componentDidUpdate(prevProps, prevState) được gọi sau mỗi lần re-render (trừ lần đầu mount). So sánh prevProps/prevState với giá trị hiện tại để quyết định có nên thực hiện side effects không. Luôn wrap code trong điều kiện `if (prevProps.id !== this.props.id)` để tránh infinite loop." },
  { id: 448, category: "React", subcategory: "Lifecycle", level: "beginner", q: "componentWillUnmount dùng để làm gì?", a: "componentWillUnmount được gọi ngay trước khi component bị xóa khỏi DOM. Dùng để cleanup: hủy subscriptions, clearTimeout/clearInterval, hủy fetch requests, xóa event listeners. Không gọi setState trong componentWillUnmount vì component sẽ không re-render nữa. Tương đương return function của useEffect." },
  { id: 449, category: "React", subcategory: "Lifecycle", level: "intermediate", q: "getDerivedStateFromProps là gì và khi nào nên tránh dùng?", a: "getDerivedStateFromProps là static method được gọi trước mỗi lần render để sync state với props. Nên tránh dùng vì dẫn đến code phức tạp và dễ gây bugs. Thay thế tốt hơn: tính giá trị derived trong render, dùng fully controlled component, hoặc dùng key prop để reset component khi cần. React team cũng khuyến cáo hạn chế dùng." },
  { id: 450, category: "React", subcategory: "Lifecycle", level: "advanced", q: "shouldComponentUpdate hoạt động như thế nào và khi nào nên dùng?", a: "shouldComponentUpdate(nextProps, nextState) trả về boolean, quyết định component có re-render hay không. Mặc định return true. Dùng để tối ưu performance bằng cách skip render khi props/state không thực sự thay đổi. React.PureComponent tự động implement với shallow comparison. Với function components, dùng React.memo thay thế." },
  { id: 451, category: "React", subcategory: "Lifecycle", level: "advanced", q: "getSnapshotBeforeUpdate dùng để làm gì?", a: "getSnapshotBeforeUpdate(prevProps, prevState) được gọi ngay trước khi DOM được cập nhật, cho phép capture thông tin từ DOM trước khi thay đổi. Giá trị trả về được pass vào componentDidUpdate như tham số thứ ba. Hay dùng để giữ scroll position trong chat app khi có message mới." },
  { id: 452, category: "React", subcategory: "Lifecycle", level: "intermediate", q: "componentDidCatch và Error Boundary liên quan như thế nào?", a: "componentDidCatch(error, info) là lifecycle method cho phép Class Component bắt lỗi từ component con trong render phase. Kết hợp với getDerivedStateFromError để tạo Error Boundary - component bắt lỗi và hiển thị fallback UI. Function components không thể là Error Boundary, phải dùng class hoặc thư viện như react-error-boundary." },
  { id: 453, category: "React", subcategory: "Lifecycle", level: "intermediate", q: "Thứ tự lifecycle methods khi component mount, update, unmount là gì?", a: "Mount: constructor → getDerivedStateFromProps → render → DOM update → componentDidMount. Update: getDerivedStateFromProps → shouldComponentUpdate → render → getSnapshotBeforeUpdate → DOM update → componentDidUpdate. Unmount: componentWillUnmount → component bị xóa. Với concurrent mode, render phase có thể bị interrupt." },
  { id: 454, category: "React", subcategory: "Lifecycle", level: "advanced", q: "Strict Mode ảnh hưởng đến lifecycle như thế nào?", a: "React.StrictMode trong development gọi một số lifecycle methods và hooks hai lần (mount, unmount, re-mount) để phát hiện side effects không thuần. componentDidMount và componentDidUpdate được gọi hai lần trong dev, nhưng một lần trong production. Hữu ích để catch bugs do side effects trong render phase." },
  { id: 455, category: "React", subcategory: "Lifecycle", level: "beginner", q: "Constructor trong Class Component dùng để làm gì?", a: "Constructor dùng để khởi tạo state và bind event handlers. Phải gọi `super(props)` đầu tiên để truy cập this.props. Trong function components, không cần constructor vì useState handles initialization. Tránh đặt side effects trong constructor, để vào componentDidMount." },

  // === React - useState & useEffect (456-475) ===
  { id: 456, category: "React", subcategory: "useState & useEffect", level: "beginner", q: "useState hook hoạt động như thế nào?", a: "useState nhận giá trị khởi tạo và trả về mảng gồm state hiện tại và setter function: `const [count, setCount] = useState(0)`. Khi gọi setter, React schedule re-render với giá trị mới. Setter có thể nhận giá trị mới trực tiếp hoặc updater function `prev => prev + 1` để tránh stale closure." },
  { id: 457, category: "React", subcategory: "useState & useEffect", level: "beginner", q: "useEffect hook dùng để làm gì?", a: "useEffect thực hiện side effects trong function components: fetch data, subscriptions, DOM manipulation, timers. Nhận callback function và dependency array. Chạy sau mỗi render (mặc định), sau render khi dependencies thay đổi (có deps array), hoặc chỉ một lần sau mount (deps array rỗng `[]`)." },
  { id: 458, category: "React", subcategory: "useState & useEffect", level: "beginner", q: "Dependency array trong useEffect có ý nghĩa gì?", a: "Dependency array kiểm soát khi nào effect chạy lại. Không có array: chạy sau mỗi render. Array rỗng `[]`: chỉ chạy sau mount, tương đương componentDidMount. Array có giá trị `[a, b]`: chạy khi a hoặc b thay đổi. React ESLint plugin exhaustive-deps giúp phát hiện missing dependencies." },
  { id: 459, category: "React", subcategory: "useState & useEffect", level: "intermediate", q: "Cleanup function trong useEffect là gì và khi nào cần dùng?", a: "Cleanup function là function được return từ useEffect, chạy trước khi effect chạy lại hoặc component unmount. Dùng để hủy subscriptions, clearTimeout, cancel fetch requests tránh memory leaks và stale updates. Ví dụ: `return () => { clearInterval(timer); subscription.unsubscribe(); }`." },
  { id: 460, category: "React", subcategory: "useState & useEffect", level: "intermediate", q: "Làm thế nào để thực hiện async operations trong useEffect?", a: "Không thể trực tiếp dùng async function làm effect callback vì nó trả về Promise, nhưng cleanup phải return void. Giải pháp: khai báo async function bên trong effect rồi gọi nó, hoặc dùng IIFE: `useEffect(() => { (async () => { const data = await fetch(url); })(); }, [])`. Luôn xử lý cleanup để cancel request nếu component unmount." },
  { id: 461, category: "React", subcategory: "useState & useEffect", level: "intermediate", q: "Làm sao tránh infinite loop trong useEffect?", a: "Infinite loop xảy ra khi effect cập nhật state mà state đó lại là dependency của effect. Giải pháp: kiểm tra dependency array có chính xác không, dùng functional updater `setCount(c => c + 1)` thay vì reference state trong effect, tách effect thành nhiều effect với dependencies khác nhau, hoặc dùng useRef để lưu giá trị mà không trigger re-render." },
  { id: 462, category: "React", subcategory: "useState & useEffect", level: "beginner", q: "Làm thế nào để fetch data với useEffect?", a: "Tạo async function bên trong effect, gọi fetch, set state với kết quả, và xử lý loading/error states. Dùng cleanup function để cancel request nếu component unmount (AbortController). Với React 18 và StrictMode, effect chạy hai lần trong dev nên cần idempotent cleanup. Hoặc dùng React Query/SWR để data fetching tốt hơn." },
  { id: 463, category: "React", subcategory: "useState & useEffect", level: "intermediate", q: "Stale closure trong useEffect là gì và cách tránh?", a: "Stale closure xảy ra khi effect capture giá trị cũ của state hoặc props vì closure bị tạo lúc render trước. Giải pháp: thêm dependencies bị thiếu vào array, dùng useRef để lưu giá trị mới nhất không cần re-run effect, hoặc dùng functional updater `setState(prev => ...)` để không cần reference state trong closure." },
  { id: 464, category: "React", subcategory: "useState & useEffect", level: "beginner", q: "Có thể có nhiều useState và useEffect trong một component không?", a: "Có thể và khuyến khích chia nhỏ state và effects theo logic. Nhiều useState giúp tách riêng state values, nhiều useEffect giúp tách side effects theo concern. React đảm bảo thứ tự hooks giữ nguyên giữa các renders (hooks không được gọi conditionally). Mỗi useEffect nên có một mục đích rõ ràng." },
  { id: 465, category: "React", subcategory: "useState & useEffect", level: "advanced", q: "Lazy initialization của useState là gì và khi nào dùng?", a: "Truyền function vào useState thay vì giá trị trực tiếp: `useState(() => computeExpensiveValue())`. Function này chỉ chạy một lần khi mount, không chạy lại mỗi render. Hữu ích khi khởi tạo state từ localStorage hay tính toán phức tạp: `useState(() => JSON.parse(localStorage.getItem('key')))`." },
  { id: 466, category: "React", subcategory: "useState & useEffect", level: "intermediate", q: "Khi nào useEffect chạy trong React 18 Strict Mode?", a: "Trong React 18 Strict Mode development, mỗi component mount-unmount-mount lại để test cleanup. Effect chạy: mount (lần 1) → cleanup → mount (lần 2). Giúp phát hiện bugs do missing cleanup. Production không bị ảnh hưởng. Code đúng cần idempotent: connect/disconnect subscription, fetch với cancel, v.v." },
  { id: 467, category: "React", subcategory: "useState & useEffect", level: "intermediate", q: "Sự khác biệt giữa useEffect và useLayoutEffect là gì?", a: "useEffect chạy asynchronously sau khi trình duyệt paint, không block UI. useLayoutEffect chạy synchronously sau DOM mutations nhưng trước khi trình duyệt paint, có thể block paint. Dùng useLayoutEffect khi cần đọc layout DOM và synchronously re-render để tránh visual flicker (ví dụ tooltips). Mặc định dùng useEffect." },
  { id: 468, category: "React", subcategory: "useState & useEffect", level: "beginner", q: "useState có thể lưu trữ kiểu dữ liệu nào?", a: "useState có thể lưu bất kỳ giá trị JavaScript nào: primitives (string, number, boolean), objects, arrays, functions, null, undefined. Với objects và arrays, phải cập nhật immutably (tạo bản sao mới) để trigger re-render. Tránh lưu dữ liệu có thể tính toán từ state khác (derived state) để tránh state sync bugs." },
  { id: 469, category: "React", subcategory: "useState & useEffect", level: "intermediate", q: "Batching updates trong function component với hooks?", a: "React 18 tự động batch tất cả state updates kể cả trong async code (setTimeout, Promise, fetch callbacks). Nhiều useState calls trong event handler hay useEffect chỉ gây một lần re-render. Dùng `flushSync` từ react-dom để force immediate re-render khi cần. Đây là improvement lớn so với React 17 chỉ batch trong event handlers." },
  { id: 470, category: "React", subcategory: "useState & useEffect", level: "advanced", q: "useInsertionEffect là gì và khi nào dùng?", a: "useInsertionEffect chạy trước bất kỳ DOM mutations nào, trước cả useLayoutEffect. Được tạo ra dành cho CSS-in-JS libraries để inject styles trước khi component render, tránh flash of unstyled content. Không nên dùng trong application code thông thường, chỉ dành cho library authors." },
  { id: 471, category: "React", subcategory: "useState & useEffect", level: "intermediate", q: "Làm thế nào để share stateful logic giữa nhiều components với useEffect?", a: "Trích xuất logic vào custom hook - function bắt đầu bằng 'use'. Custom hook có thể gọi useState, useEffect và các hooks khác. Component sử dụng custom hook sẽ có state riêng biệt, không chia sẻ instance. Ví dụ: useWindowSize(), useDebounce(), useFetch() đều là custom hooks phổ biến." },
  { id: 472, category: "React", subcategory: "useState & useEffect", level: "beginner", q: "useState setter function có bao giờ thay đổi reference không?", a: "Không, setter function từ useState có reference ổn định giữa các renders. Vì vậy không cần thêm setter vào useEffect dependency array. Điều này khác với functions tự khai báo trong component body (tạo mới mỗi render). React đảm bảo setter identity stable để tối ưu performance." },
  { id: 473, category: "React", subcategory: "useState & useEffect", level: "intermediate", q: "Khi nào React bail out (bỏ qua) re-render khi gọi setState?", a: "React bail out nếu giá trị mới giống hệt giá trị hiện tại (sử dụng Object.is comparison). Ví dụ: `setCount(count)` với cùng value sẽ không trigger re-render. Tuy nhiên React vẫn có thể render component một lần để verify trước khi bail out hoàn toàn. Hữu ích để tối ưu performance." },
  { id: 474, category: "React", subcategory: "useState & useEffect", level: "advanced", q: "useEffect với object dependencies có vấn đề gì?", a: "Object dependencies tạo infinite loop vì mỗi render tạo object literal mới có reference khác, React compare by reference không phải by value. Giải pháp: destructure primitive values từ object làm deps `[obj.id, obj.name]`, dùng useMemo để memoize object, hoặc dùng useRef để lưu object. Tương tự với array và function dependencies." },
  { id: 475, category: "React", subcategory: "useState & useEffect", level: "intermediate", q: "Cách đúng để fetch data và xử lý race conditions trong useEffect?", a: "Dùng AbortController để cancel fetch request cũ khi effect re-run: `const controller = new AbortController(); fetch(url, { signal: controller.signal }); return () => controller.abort()`. Hoặc dùng boolean flag `let cancelled = false` trong cleanup. React Query và SWR tự động handle race conditions." },

  // === React - Advanced Hooks (476-495) ===
  { id: 476, category: "React", subcategory: "Advanced Hooks", level: "intermediate", q: "useContext hook là gì và cách sử dụng?", a: "useContext nhận vào Context object và trả về giá trị context hiện tại. Phải đặt component bên trong Provider tương ứng. Khi context value thay đổi, mọi component dùng useContext sẽ re-render. Thay thế cho Context.Consumer và thích hợp hơn trong function components." },
  { id: 477, category: "React", subcategory: "Advanced Hooks", level: "intermediate", q: "useReducer khác gì useState và khi nào nên dùng?", a: "useReducer(`reducer, initialState`) phù hợp khi: state logic phức tạp với nhiều sub-values, state transition phụ thuộc vào state trước, hay nhiều actions khác nhau cập nhật state theo cách khác nhau. Giống Redux pattern với dispatch/action/reducer. Khi state là object với nhiều fields liên quan, useReducer thường sạch hơn nhiều useState." },
  { id: 478, category: "React", subcategory: "Advanced Hooks", level: "intermediate", q: "useMemo hook dùng để làm gì? Khi nào nên dùng?", a: "useMemo memoize kết quả tính toán tốn kém, chỉ tính lại khi dependencies thay đổi: `useMemo(() => expensiveCalc(a, b), [a, b])`. Dùng khi: có tính toán expensive mà không muốn chạy lại mỗi render, cần stable object reference cho dependency array của effect hay prop của React.memo component. Không nên dùng quá mức vì có overhead riêng." },
  { id: 479, category: "React", subcategory: "Advanced Hooks", level: "intermediate", q: "useCallback hook dùng để làm gì? Khác gì useMemo?", a: "useCallback memoize function để giữ stable reference giữa renders: `useCallback(() => fn, deps)`. Tương đương `useMemo(() => fn, deps)` nhưng rõ ràng hơn. Dùng khi truyền callback xuống child component được wrap bởi React.memo, hoặc khi function là dependency của useEffect. Không cần cho hầu hết event handlers thông thường." },
  { id: 480, category: "React", subcategory: "Advanced Hooks", level: "intermediate", q: "useRef hook có những công dụng gì?", a: "useRef trả về mutable ref object với `.current` property không trigger re-render khi thay đổi. Hai công dụng chính: (1) truy cập DOM element trực tiếp `const inputRef = useRef(null); <input ref={inputRef} />` để focus/measure; (2) lưu giá trị mutable giữa renders mà không cần re-render như timerId, previous value, hay event handler reference." },
  { id: 481, category: "React", subcategory: "Advanced Hooks", level: "advanced", q: "useId hook là gì và khi nào dùng?", a: "useId (React 18) tạo unique ID ổn định giữa server và client, giải quyết hydration mismatch khi dùng Math.random() hay counter. Dùng cho: nối input với label qua id/htmlFor, ARIA attributes cần unique IDs. Không dùng làm key trong danh sách. Prefix với CSS prefix nếu cần: `id={id + '-input'}`." },
  { id: 482, category: "React", subcategory: "Advanced Hooks", level: "intermediate", q: "useLayoutEffect khác useEffect như thế nào và khi nào dùng?", a: "useLayoutEffect chạy synchronously sau DOM update nhưng trước browser paint, blocking. useEffect chạy asynchronously sau paint, non-blocking. Dùng useLayoutEffect khi: cần đọc layout và synchronously set style/position để tránh visual flicker, ví dụ tooltip positioning. Server rendering: useLayoutEffect không chạy trên server, cần fallback." },
  { id: 483, category: "React", subcategory: "Advanced Hooks", level: "advanced", q: "useTransition hook dùng để làm gì?", a: "useTransition (React 18) cho phép đánh dấu state update là non-urgent, React có thể interrupt và ưu tiên urgent updates trước. Trả về `[isPending, startTransition]`. Dùng khi: filtering danh sách lớn, heavy re-renders mà không muốn block UI cho urgent input. Ví dụ: typing vào search box (urgent) + updating results (transition)." },
  { id: 484, category: "React", subcategory: "Advanced Hooks", level: "advanced", q: "useDeferredValue hook là gì?", a: "useDeferredValue (React 18) trả về phiên bản deferred của giá trị, React có thể giữ giá trị cũ khi render expensive component trong khi urgent update hoàn thành. Khác useTransition: không wrap update code, wrap giá trị result. Tốt khi không control code cập nhật state (nhận từ props). Kết hợp với React.memo để maximize benefit." },
  { id: 485, category: "React", subcategory: "Advanced Hooks", level: "advanced", q: "useImperativeHandle hook dùng để làm gì?", a: "useImperativeHandle kết hợp với forwardRef để tùy chỉnh những gì parent nhìn thấy qua ref, thay vì expose toàn bộ DOM node. Ví dụ: expose chỉ `focus()` và `scrollIntoView()` thay vì toàn bộ input element. Giúp đóng gói internal implementation, chỉ expose API cần thiết. Dùng khi cần imperative API từ component." },
  { id: 486, category: "React", subcategory: "Advanced Hooks", level: "intermediate", q: "useDebugValue hook dùng để làm gì?", a: "useDebugValue hiển thị label tùy chỉnh cho custom hook trong React DevTools. Hữu ích khi debug complex custom hooks để thấy state hiện tại. Nhận giá trị hoặc format function (để lazy format chỉ khi DevTools mở). Chỉ cần dùng trong custom hooks được chia sẻ, không cần cho internal hooks." },
  { id: 487, category: "React", subcategory: "Advanced Hooks", level: "advanced", q: "useSyncExternalStore hook là gì?", a: "useSyncExternalStore (React 18) là hook chính thức để subscribe external stores (Redux, Zustand, browser APIs) đảm bảo consistent reads trong concurrent mode. Thay thế manual subscription trong useEffect. Nhận subscribe function và getSnapshot function. Libraries như Redux đã migrate sang hook này thay vì useEffect-based subscription." },
  { id: 488, category: "React", subcategory: "Advanced Hooks", level: "intermediate", q: "Quy tắc của Hooks (Rules of Hooks) là gì?", a: "Hai quy tắc: (1) Chỉ gọi hooks ở top level - không trong loops, conditions, nested functions để React track order. (2) Chỉ gọi hooks trong React function components hoặc custom hooks, không trong regular JS functions. ESLint plugin eslint-plugin-react-hooks tự động enforce các quy tắc này." },
  { id: 489, category: "React", subcategory: "Advanced Hooks", level: "intermediate", q: "Tại sao hooks không thể gọi conditionally?", a: "React theo dõi hooks theo thứ tự gọi trong mỗi render. Nếu gọi conditional, thứ tự thay đổi giữa các renders và React không biết hook nào tương ứng với state nào. Lỗi sẽ xảy ra và state bị sai. Thay vào đó, đặt conditional bên trong hook nếu cần: `useEffect(() => { if (condition) { ... } }, [condition])`." },
  { id: 490, category: "React", subcategory: "Advanced Hooks", level: "advanced", q: "useOptimistic hook (React 19) là gì?", a: "useOptimistic cho phép hiển thị state tạm thời (optimistic) ngay lập tức khi user hành động, trước khi server response. Nếu action thất bại, tự động rollback về state thực. Cú pháp: `const [optimisticMessages, addOptimistic] = useOptimistic(messages, (state, newMsg) => [...state, newMsg])`. Cải thiện perceived performance." },
  { id: 491, category: "React", subcategory: "Advanced Hooks", level: "advanced", q: "useActionState hook (React 19) là gì?", a: "useActionState (trước là useFormState trong React DOM) quản lý state của form action, trả về `[state, dispatch, isPending]`. Tích hợp với Server Actions trong Next.js. Thay thế pattern thủ công quản lý loading/error state khi submit form. Tự động handle pending state và error state từ action." },
  { id: 492, category: "React", subcategory: "Advanced Hooks", level: "intermediate", q: "Cách tối ưu useContext để tránh re-render không cần thiết?", a: "Khi context value thay đổi, mọi consumer re-render dù chỉ dùng một phần. Tối ưu: tách context thành nhiều context nhỏ hơn theo concern, memoize context value với useMemo, dùng context selector pattern hay thư viện như use-context-selector. Ngoài ra, split static và dynamic context riêng biệt." },
  { id: 493, category: "React", subcategory: "Advanced Hooks", level: "intermediate", q: "useReducer kết hợp useContext để thay thế Redux như thế nào?", a: "Pattern: tạo Context với value là `{ state, dispatch }`, dùng useReducer quản lý state, bọc app trong Provider. Consumers dùng useContext để lấy state và dispatch actions. Phù hợp cho state management vừa và nhỏ. Khác Redux: không có middleware, devtools kém hơn, không serialize actions. Redux vẫn tốt hơn cho large apps." },
  { id: 494, category: "React", subcategory: "Advanced Hooks", level: "advanced", q: "useEvent hook (RFC) giải quyết vấn đề gì?", a: "useEvent RFC đã withdrawn, thay bằng `useEffectEvent` (experimental React 18.3+). Giải quyết: cần function stable reference nhưng luôn đọc props/state mới nhất. useCallback tạo stable ref nhưng stale closure. Workaround hiện tại: dùng useRef để lưu function mới nhất, hoặc chờ useEffectEvent stable." },
  { id: 495, category: "React", subcategory: "Advanced Hooks", level: "intermediate", q: "Sự khác biệt giữa useMemo và React.memo là gì?", a: "useMemo là hook memoize giá trị/kết quả tính toán bên trong component. React.memo là HOC memoize toàn bộ component, skip re-render khi props không thay đổi (shallow comparison). Kết hợp cả hai: dùng React.memo cho component, useCallback cho callback props để React.memo hoạt động hiệu quả." },

  // === React - Custom Hooks (496-505) ===
  { id: 496, category: "React", subcategory: "Custom Hooks", level: "intermediate", q: "Custom hook là gì và cách tạo?", a: "Custom hook là JavaScript function bắt đầu bằng 'use' có thể gọi các hooks khác. Dùng để tái sử dụng stateful logic giữa components. Mỗi component sử dụng custom hook có state instance riêng biệt, không chia sẻ. Ví dụ: `function useLocalStorage(key, initial) { const [value, setValue] = useState(...); return [value, setValue]; }`." },
  { id: 497, category: "React", subcategory: "Custom Hooks", level: "intermediate", q: "Tại sao custom hook phải bắt đầu bằng 'use'?", a: "Quy ước 'use' prefix là contract với React và linter: nó nói với React rằng function này có thể gọi hooks bên trong. ESLint plugin react-hooks/rules-of-hooks chỉ kiểm tra functions có prefix 'use'. Không bắt đầu bằng 'use' có nghĩa là function không tuân theo rules of hooks và linter sẽ không cảnh báo nếu vi phạm." },
  { id: 498, category: "React", subcategory: "Custom Hooks", level: "intermediate", q: "Khi nào nên tách logic vào custom hook so với utility function?", a: "Dùng custom hook khi logic cần: React hooks (useState, useEffect, v.v.), React lifecycle, hay stateful behavior. Dùng utility function (pure function) khi: chỉ xử lý data transformation, validation, formatting - không cần React context. Custom hook gọi được từ components, utility function gọi từ bất cứ đâu." },
  { id: 499, category: "React", subcategory: "Custom Hooks", level: "intermediate", q: "Viết custom hook useDebounce như thế nào?", a: "useDebounce delay việc cập nhật value cho đến khi user ngừng thay đổi trong khoảng thời gian nhất định: `function useDebounce(value, delay) { const [debounced, setDebounced] = useState(value); useEffect(() => { const timer = setTimeout(() => setDebounced(value), delay); return () => clearTimeout(timer); }, [value, delay]); return debounced; }`." },
  { id: 500, category: "React", subcategory: "Custom Hooks", level: "advanced", q: "Làm thế nào để test custom hooks?", a: "Dùng @testing-library/react với `renderHook` utility: `const { result } = renderHook(() => useMyHook()); expect(result.current.value).toBe(expected)`. Để test interactions: `act(() => { result.current.setValue('new') })`. Với async hooks dùng `waitFor`. `renderHook` tạo component test wrapper để hooks có React context đầy đủ." },
  { id: 501, category: "React", subcategory: "Custom Hooks", level: "intermediate", q: "usePrevious hook làm gì và cách implement?", a: "usePrevious lưu giá trị trước đó của một value sử dụng useRef. Sau mỗi render, ref được cập nhật với value hiện tại nhưng function trả về ref.current (value từ render trước): `function usePrevious(value) { const ref = useRef(undefined); useEffect(() => { ref.current = value; }); return ref.current; }`. React 19 yêu cầu truyền giá trị khởi tạo cho useRef, dùng undefined nếu không có giá trị ban đầu phù hợp." },
  { id: 502, category: "React", subcategory: "Custom Hooks", level: "intermediate", q: "useFetch custom hook nên xử lý những trường hợp nào?", a: "useFetch nên handle: loading state, error state, data state, abort on unmount (AbortController), refetch capability, caching tùy chọn. Nên tránh: không xử lý race conditions, không handle 4xx/5xx HTTP errors riêng biệt. Thực tế, dùng React Query hoặc SWR tốt hơn tự viết vì chúng xử lý tất cả edge cases." },
  { id: 503, category: "React", subcategory: "Custom Hooks", level: "advanced", q: "Composition của custom hooks là gì?", a: "Custom hooks có thể gọi custom hooks khác, tạo composable layers. Ví dụ: useUser gọi useFetch, useCache, useAuth. Pattern này giống function composition, cho phép xây dựng complex behaviors từ simple hooks. Giữ mỗi hook single-responsibility, tránh hooks quá fat có nhiều trách nhiệm không liên quan." },
  { id: 504, category: "React", subcategory: "Custom Hooks", level: "intermediate", q: "Custom hook có thể return gì?", a: "Custom hook có thể return bất cứ thứ gì: object `{ value, setValue }`, array `[value, handler]` (như useState), single value, function, hay void. Convention: return array khi có 2 giá trị đơn giản (như useState), return object khi có nhiều named values. Tên phải mô tả ý nghĩa rõ ràng." },
  { id: 505, category: "React", subcategory: "Custom Hooks", level: "advanced", q: "Patterns hay được dùng trong custom hooks là gì?", a: "Các patterns phổ biến: (1) State + Actions pattern (return state và handlers), (2) Observer pattern (subscribe/unsubscribe), (3) Factory pattern (nhận config tạo ra hook instance khác nhau), (4) Composition (gọi nhiều hooks nhỏ), (5) Bridge pattern (kết nối external library với React world). usehooks.com là nguồn tham khảo tốt." },

  // === React - Context & Router (506-520) ===
  { id: 506, category: "React", subcategory: "Context & Router", level: "intermediate", q: "Context API trong React là gì và giải quyết vấn đề gì?", a: "Context API cho phép chia sẻ dữ liệu (theme, language, auth, user) qua component tree mà không cần pass props qua từng cấp trung gian (props drilling). Gồm ba phần: React.createContext(), Context.Provider (bọc tree cung cấp value), useContext (consume value trong bất kỳ component con nào)." },
  { id: 507, category: "React", subcategory: "Context & Router", level: "intermediate", q: "Provider và Consumer trong Context API hoạt động như thế nào?", a: "Provider bọc phần tree cần access context, cung cấp value: `<ThemeContext.Provider value={theme}>`. Consumer là cách cũ để đọc context dùng render props pattern. useContext hook là cách hiện đại thay Consumer, ngắn gọn hơn nhiều. Khi Provider value thay đổi, tất cả consumers re-render." },
  { id: 508, category: "React", subcategory: "Context & Router", level: "intermediate", q: "Khi nào nên dùng Context thay vì props drilling?", a: "Dùng Context khi: dữ liệu cần ở nhiều levels sâu (theme, locale, auth), data được nhiều components dùng, props chỉ passed qua để forward (không dùng ở cấp trung gian). Không nên dùng cho state thay đổi thường xuyên vì gây nhiều re-renders. Props drilling 2-3 cấp thì không cần Context." },
  { id: 509, category: "React", subcategory: "Context & Router", level: "intermediate", q: "React Router là gì và cách hoạt động?", a: "React Router là thư viện routing phổ biến nhất cho React SPA. Dựa trên history API của browser, sync URL với component tree. Components chính: BrowserRouter (provider), Routes/Route (mapping URL đến component), Link (navigation không reload). Phiên bản v6 thay đổi nhiều so với v5 với nested routes và outlet." },
  { id: 510, category: "React", subcategory: "Context & Router", level: "beginner", q: "Sự khác biệt giữa Link và anchor tag trong React Router?", a: "Link component của React Router ngăn browser reload trang, thay vào đó cập nhật history và render component tương ứng - đây là SPA behavior. Anchor tag `<a href>` thực hiện full page reload, reset React state hoàn toàn. Dùng Link cho internal navigation, anchor tag cho external links." },
  { id: 511, category: "React", subcategory: "Context & Router", level: "intermediate", q: "useParams hook trong React Router dùng để làm gì?", a: "useParams trả về object chứa URL parameters của route đang active. Ví dụ: route `/users/:id` thì `useParams()` trả về `{ id: '123' }`. Cần import từ react-router-dom. Với TypeScript, dùng `useParams<{ id: string }>()` để type-safe." },
  { id: 512, category: "React", subcategory: "Context & Router", level: "intermediate", q: "useNavigate hook trong React Router v6 dùng như thế nào?", a: "useNavigate trả về navigate function để programmatically điều hướng: `navigate('/path')`, `navigate(-1)` (back), `navigate('/path', { replace: true })`. Thay thế cho useHistory trong v5. Dùng khi cần navigate sau form submit, sau auth login, hay trong event handlers không phải JSX." },
  { id: 513, category: "React", subcategory: "Context & Router", level: "intermediate", q: "Nested routes trong React Router v6 hoạt động như thế nào?", a: "Nested routes dùng `<Outlet />` component để render child routes. Parent route render layout, Outlet là nơi child route render: `<Route path='/dashboard' element={<DashboardLayout />}><Route index element={<Overview />} /><Route path='settings' element={<Settings />} /></Route>`. Child route paths relative, không cần lặp lại parent path." },
  { id: 514, category: "React", subcategory: "Context & Router", level: "intermediate", q: "Protected routes trong React Router được implement như thế nào?", a: "Tạo wrapper component check auth, redirect nếu chưa đăng nhập: `function PrivateRoute({ children }) { const auth = useAuth(); return auth.isLoggedIn ? children : <Navigate to='/login' replace /> }`. Dùng trong Route: `<Route path='/dashboard' element={<PrivateRoute><Dashboard /></PrivateRoute>} />`. Navigate component thay Redirect của v5." },
  { id: 515, category: "React", subcategory: "Context & Router", level: "beginner", q: "useLocation hook trong React Router trả về gì?", a: "useLocation trả về object location hiện tại gồm: pathname (URL path), search (query string), hash, state (data được pass qua navigate). Hữu ích để: đọc query params (kết hợp URLSearchParams), track page views analytics, xử lý redirect after login (lưu intended URL vào state)." },
  { id: 516, category: "React", subcategory: "Context & Router", level: "intermediate", q: "Multiple contexts trong một app được tổ chức như thế nào?", a: "Tổ chức nhiều context bằng cách: tạo nhiều Provider riêng biệt, nest chúng lại (thứ tự từ ngoài vào trong), hoặc tạo AppProviders component bọc tất cả providers. Mỗi context chịu trách nhiệm một concern (AuthContext, ThemeContext, CartContext). Tránh god context chứa tất cả global state." },
  { id: 517, category: "React", subcategory: "Context & Router", level: "advanced", q: "Context re-render optimization là gì?", a: "Khi context value object được tạo mới mỗi render, tất cả consumers re-render dù giá trị thực không đổi. Fix: memoize value với useMemo `useMemo(() => ({ user, logout }), [user])`, tách state context và dispatch context riêng, dùng libraries như jotai/zustand tránh context re-render issues. Structural sharing giúp nhưng không đủ." },
  { id: 518, category: "React", subcategory: "Context & Router", level: "intermediate", q: "Default value của createContext dùng khi nào?", a: "Default value của `React.createContext(defaultValue)` chỉ dùng khi component consume context không có Provider nào bên trên. Hữu ích cho testing (không cần wrap với Provider) và cho components hoạt động độc lập. Trong production, thường luôn có Provider nên default value ít khi được dùng." },
  { id: 519, category: "React", subcategory: "Context & Router", level: "intermediate", q: "React Router SearchParams (query strings) được xử lý như thế nào?", a: "Dùng useSearchParams hook: `const [searchParams, setSearchParams] = useSearchParams()`. Đọc: `searchParams.get('tab')`. Cập nhật: `setSearchParams({ tab: 'new' })` hay `setSearchParams(prev => { prev.set('tab', 'new'); return prev; })`. Phù hợp cho filter, pagination state cần share qua URL." },
  { id: 520, category: "React", subcategory: "Context & Router", level: "advanced", q: "Data loading với React Router v6.4+ loader functions là gì?", a: "React Router v6.4 giới thiệu loader function cho Route để fetch data trước khi render component: `{ path: '/users/:id', loader: ({ params }) => fetchUser(params.id), element: <UserDetail /> }`. Dùng `useLoaderData()` trong component để access data. Xử lý loading/error states qua errorElement. Tương tự Next.js data fetching pattern." },

  // === React - Forms & Error (521-535) ===
  { id: 521, category: "React", subcategory: "Forms & Error", level: "beginner", q: "Controlled component trong form là gì?", a: "Controlled component là input có giá trị được kiểm soát hoàn toàn bởi React state. Value bind với state, onChange cập nhật state: `<input value={name} onChange={e => setName(e.target.value)} />`. Mọi thay đổi đi qua React, cho phép validate, transform, hay conditional disable dễ dàng." },
  { id: 522, category: "React", subcategory: "Forms & Error", level: "intermediate", q: "Uncontrolled component và useRef trong form là gì?", a: "Uncontrolled component lưu giá trị trong DOM, không sync với React state. Dùng ref để đọc khi cần (submit): `const inputRef = useRef(null); <input ref={inputRef} />`. Kể từ React 19, useRef yêu cầu truyền giá trị khởi tạo (thường là null cho DOM refs). Đơn giản hơn cho form không cần real-time validation, nhưng khó tích hợp với validation libraries." },
  { id: 523, category: "React", subcategory: "Forms & Error", level: "intermediate", q: "Formik là gì và tại sao sử dụng nó?", a: "Formik là thư viện quản lý form state, validation, và submission trong React. Xử lý: touched/dirty states, error messages, submission handling, field-level và form-level validation. Giảm boilerplate code đáng kể so với quản lý state thủ công. Tích hợp tốt với Yup cho schema validation." },
  { id: 524, category: "React", subcategory: "Forms & Error", level: "intermediate", q: "React Hook Form khác Formik như thế nào?", a: "React Hook Form dùng uncontrolled components và refs thay vì state, nên ít re-renders hơn (performance tốt hơn). API đơn giản hơn với register, handleSubmit, formState. Bundle size nhỏ hơn Formik. Formik dễ học hơn với explicit controlled pattern. RHF được cộng đồng ưa chuộng hơn cho performance-critical forms." },
  { id: 525, category: "React", subcategory: "Forms & Error", level: "intermediate", q: "Form validation trong React được thực hiện như thế nào?", a: "Các cách: (1) Manual: check trong onChange/onSubmit, lưu errors vào state. (2) HTML5 built-in: required, minLength, pattern attributes. (3) Formik + Yup: declarative schema validation. (4) React Hook Form với resolver (Yup, Zod). Dùng Zod cho type-safe validation kết hợp TypeScript là best practice hiện đại." },
  { id: 526, category: "React", subcategory: "Forms & Error", level: "beginner", q: "onSubmit handler trong React form ngăn reload page như thế nào?", a: "Gọi `event.preventDefault()` trong onSubmit handler để ngăn browser reload page (hành vi mặc định của form submit). Sau đó xử lý data trong JavaScript: validate, gọi API, cập nhật state. Nếu dùng React Hook Form, `handleSubmit(onSubmit)` tự động gọi preventDefault." },
  { id: 527, category: "React", subcategory: "Forms & Error", level: "intermediate", q: "Error Boundary là gì và cách tạo?", a: "Error Boundary là React component bắt JavaScript errors trong component tree con và hiển thị fallback UI thay vì crash toàn app. Chỉ có thể tạo với Class Component implement `getDerivedStateFromError` (set error state) và `componentDidCatch` (log error). Thư viện react-error-boundary cung cấp `ErrorBoundary` component tiện dụng hơn." },
  { id: 528, category: "React", subcategory: "Forms & Error", level: "intermediate", q: "Error Boundary không bắt được lỗi nào?", a: "Error Boundary không bắt: errors trong event handlers (phải try/catch thủ công), async code (setTimeout, Promises), server-side rendering, errors trong chính Error Boundary component. Chỉ bắt errors trong render phase, lifecycle methods, constructors của component tree bên dưới." },
  { id: 529, category: "React", subcategory: "Forms & Error", level: "advanced", q: "Làm thế nào để handle form với file upload trong React?", a: "Input type file phải là uncontrolled (không dùng value, dùng onChange để đọc files). Đọc files qua `e.target.files` (FileList object). Tạo FormData để gửi: `const fd = new FormData(); fd.append('file', file)`. Hiển thị preview với `URL.createObjectURL(file)`. Nhớ revoke URL sau khi dùng để tránh memory leak." },
  { id: 530, category: "React", subcategory: "Forms & Error", level: "intermediate", q: "Dynamic form fields (thêm xóa input fields) được implement như thế nào?", a: "Lưu array of field objects trong state. Render với map, mỗi field có unique id làm key. Thêm: `setFields(prev => [...prev, { id: uuid(), value: '' }])`. Xóa: `setFields(prev => prev.filter(f => f.id !== id))`. React Hook Form cung cấp useFieldArray hook xử lý pattern này với performance tốt hơn." },
  { id: 531, category: "React", subcategory: "Forms & Error", level: "beginner", q: "Làm thế nào để handle select, checkbox, radio trong React?", a: "Select: value bind với state, onChange cập nhật. Multi-select: value nhận array, onChange đọc selectedOptions. Checkbox: dùng `checked` thay `value`, onChange nhận `e.target.checked`. Radio group: mỗi radio có value, checked so sánh với state, onChange set state với value. Controlled pattern áp dụng tương tự cho tất cả." },
  { id: 532, category: "React", subcategory: "Forms & Error", level: "advanced", q: "Optimistic UI trong form submission là gì?", a: "Optimistic UI cập nhật UI ngay lập tức trước khi server confirm, giả định success. Nếu server thất bại, rollback về state trước. Cải thiện perceived performance. Implement: update local state trước khi gọi API, trong catch block rollback state và hiển thị error. React 19 useOptimistic hook simplifies pattern này." },
  { id: 533, category: "React", subcategory: "Forms & Error", level: "intermediate", q: "Form accessibility (a11y) trong React cần lưu ý gì?", a: "Cần: label liên kết với input qua htmlFor/id hoặc aria-label, error messages có aria-describedby, required fields có aria-required hoặc required attribute, disabled buttons không dùng pointer-events:none mà dùng disabled attribute, focus management khi modal mở/đóng. React ARIA library từ Adobe cung cấp accessible primitives." },
  { id: 534, category: "React", subcategory: "Forms & Error", level: "intermediate", q: "Zod integration với React Hook Form như thế nào?", a: "Dùng @hookform/resolvers/zod với zodResolver: `const { register, handleSubmit } = useForm({ resolver: zodResolver(schema) })`. Define schema: `const schema = z.object({ email: z.string().email(), age: z.number().min(18) })`. Errors type-safe từ Zod được truyền vào formState.errors. Cách tiếp cận hiện đại nhất cho type-safe forms." },
  { id: 535, category: "React", subcategory: "Forms & Error", level: "advanced", q: "Server-side form validation vs client-side validation khi nào dùng cái nào?", a: "Client-side validation: UX tốt hơn, instant feedback, giảm unnecessary server requests. KHÔNG thể thay thế server-side vì user có thể bypass. Server-side validation: bắt buộc cho security, validate business rules phức tạp, kiểm tra database constraints. Best practice: cả hai - client để UX, server để security và correctness." },

  // === React - Performance & Patterns (536-550) ===
  { id: 536, category: "React", subcategory: "Performance & Patterns", level: "intermediate", q: "React.memo là gì và cách hoạt động?", a: "React.memo là HOC memoize function component, skip re-render nếu props không thay đổi (shallow comparison). `const MemoButton = React.memo(Button)`. Nên dùng khi: component render expensive, props ít thay đổi, component được render thường xuyên bởi parent. Cần kết hợp với useCallback cho function props để có hiệu quả." },
  { id: 537, category: "React", subcategory: "Performance & Patterns", level: "intermediate", q: "React.lazy và Suspense dùng để làm gì?", a: "React.lazy cho phép lazy load component, chỉ download JavaScript khi component cần render: `const LazyComp = React.lazy(() => import('./HeavyComponent'))`. Suspense là wrapper hiển thị fallback UI trong khi component đang load: `<Suspense fallback={<Spinner />}><LazyComp /></Suspense>`. Giúp code splitting, giảm initial bundle size." },
  { id: 538, category: "React", subcategory: "Performance & Patterns", level: "intermediate", q: "Virtual DOM trong React là gì?", a: "Virtual DOM là representation trong memory của DOM thực. Khi state thay đổi, React tạo Virtual DOM mới, so sánh (diff) với Virtual DOM cũ, tính ra minimal set of changes, rồi áp dụng vào DOM thực (reconciliation). Giúp tối ưu DOM operations tốn kém, nhưng không phải lúc nào cũng nhanh hơn direct DOM manipulation." },
  { id: 539, category: "React", subcategory: "Performance & Patterns", level: "advanced", q: "React Fiber là gì?", a: "React Fiber là reimplementation của React's reconciliation algorithm (React 16+). Cho phép chia nhỏ rendering work thành units, có thể pause, resume, hay abort. Enables: incremental rendering, priority-based updates, concurrent features (Suspense, useTransition). Giải quyết vấn đề previous stack reconciler không thể interrupt render." },
  { id: 540, category: "React", subcategory: "Performance & Patterns", level: "intermediate", q: "HOC (Higher Order Component) là gì?", a: "HOC là function nhận component và return component mới được enhanced: `function withAuth(Component) { return function AuthWrapper(props) { ... } }`. Pattern phổ biến cho: authentication, logging, data fetching, với-conditional rendering. Hiện nay Hooks thường thay thế nhiều use cases của HOC vì đơn giản và composable hơn." },
  { id: 541, category: "React", subcategory: "Performance & Patterns", level: "intermediate", q: "Render props pattern là gì?", a: "Render props là technique chia sẻ code giữa components dùng prop là function trả về React element. Component nhận function prop gọi nó với internal state/logic: `<Mouse render={({ x, y }) => <Cat x={x} y={y} />} />`. Linh hoạt hơn HOC vì tránh naming collisions. Custom hooks giờ thường là giải pháp cleaner hơn." },
  { id: 542, category: "React", subcategory: "Performance & Patterns", level: "advanced", q: "Reconciliation algorithm trong React hoạt động như thế nào?", a: "React dùng heuristic O(n) algorithm thay vì O(n³) để diff trees: (1) Elements khác type → destroy và rebuild hoàn toàn. (2) Cùng type → compare props, update chỉ những gì thay đổi. (3) Lists dùng key để match elements giữa renders. Hiểu algorithm giúp tránh bugs và tối ưu performance." },
  { id: 543, category: "React", subcategory: "Performance & Patterns", level: "intermediate", q: "Code splitting trong React được thực hiện như thế nào?", a: "Code splitting chia bundle thành nhiều chunks, load on demand. React.lazy + dynamic import là cách chính. Route-level splitting phổ biến nhất: mỗi route là lazy-loaded component. Webpack/Vite tự động tạo chunks tách biệt. next/dynamic trong Next.js cho SSR-compatible lazy loading." },
  { id: 544, category: "React", subcategory: "Performance & Patterns", level: "intermediate", q: "Windowing/virtualization trong React là gì?", a: "Virtualization chỉ render items hiện trong viewport, không render toàn bộ danh sách hàng nghìn items. Thư viện: react-window (lightweight), react-virtualized (feature-rich). Giảm DOM nodes từ hàng nghìn xuống chỉ ~20-50. Cần thiết khi render danh sách lớn (>100 items) gây performance issues." },
  { id: 545, category: "React", subcategory: "Performance & Patterns", level: "beginner", q: "React DevTools dùng để làm gì?", a: "React DevTools là browser extension cho phép: inspect component tree, xem props và state, profile renders để tìm bottlenecks, highlight components khi re-render. Profiler tab ghi lại render timing, giúp identify slow components. Kết hợp với React.memo và useCallback để tối ưu dựa trên dữ liệu thực tế." },
  { id: 546, category: "React", subcategory: "Performance & Patterns", level: "advanced", q: "Concurrent Mode trong React là gì?", a: "Concurrent Mode (React 18) cho phép React làm việc trên nhiều versions của UI đồng thời, prioritize urgent updates. Rendering có thể interrupt để handle urgent updates. Cho phép features như Suspense for data fetching, useTransition, useDeferredValue. Enabled bằng createRoot thay vì ReactDOM.render." },
  { id: 547, category: "React", subcategory: "Performance & Patterns", level: "intermediate", q: "Tại sao không nên tạo component trong component (inline components)?", a: "Định nghĩa component bên trong component khác tạo new component type mỗi render, React unmount/remount thay vì update, gây mất state và performance issues. Luôn khai báo components ở top-level module, hoặc ngoài parent component. Nếu cần data từ parent, truyền qua props hoặc dùng children pattern." },
  { id: 548, category: "React", subcategory: "Performance & Patterns", level: "advanced", q: "Suspense for data fetching hoạt động như thế nào?", a: "Component throw Promise khi data chưa ready, Suspense catch Promise và show fallback, khi Promise resolve React retry render component. Hiện tại chính thức support với React.lazy và frameworks như Next.js (Server Components), React Query experimental. Cho phép colocate loading states với components cần data." },
  { id: 549, category: "React", subcategory: "Performance & Patterns", level: "intermediate", q: "Key prop dùng để reset component state như thế nào?", a: "Thay đổi key của component khiến React unmount component cũ và mount component mới hoàn toàn, reset tất cả state. Kỹ thuật hữu ích để: reset form sau submit `<Form key={formKey} />`, reset uncontrolled component khi data source thay đổi. Đây là cách React có ý muốn để 'reset' component state từ bên ngoài." },
  { id: 550, category: "React", subcategory: "Performance & Patterns", level: "advanced", q: "React Server Components khác Client Components như thế nào?", a: "Server Components render trên server, không có state/effects/event handlers, có thể trực tiếp access database và file system, không thêm bundle size JavaScript. Client Components (với 'use client') chạy trên browser, có interactivity. Server Components được giới thiệu trong React 18 và là nền tảng của Next.js App Router." },

  // === Next.js - App Router (551-560) ===
  { id: 551, category: "Next.js", subcategory: "App Router", level: "intermediate", q: "App Router khác Pages Router trong Next.js như thế nào?", a: "App Router (Next.js 13+) dùng thư mục `app/`, hỗ trợ React Server Components mặc định, có nested layouts, loading/error states tích hợp. Pages Router dùng thư mục `pages/`, mọi component là Client Component, có getStaticProps/getServerSideProps. App Router là tương lai của Next.js với nhiều tính năng mới." },
  { id: 552, category: "Next.js", subcategory: "App Router", level: "beginner", q: "File-based routing trong Next.js App Router hoạt động như thế nào?", a: "Trong thư mục `app/`, mỗi thư mục đại diện cho một route segment. `page.tsx` là component hiển thị cho route đó. `[param]` là dynamic segment. `(group)` là route group không ảnh hưởng URL. `[...slug]` là catch-all. File conventions: page.tsx, layout.tsx, loading.tsx, error.tsx, not-found.tsx." },
  { id: 553, category: "Next.js", subcategory: "App Router", level: "intermediate", q: "Layouts trong Next.js App Router là gì?", a: "Layout là UI chia sẻ giữa nhiều pages, preserve state khi navigate (không remount). `layout.tsx` nhận `children` prop. Nested layouts: layout lồng trong layout tạo hierarchy. Root layout (`app/layout.tsx`) bắt buộc phải có, wrap toàn app. Khác với template.tsx: template remount mỗi navigate." },
  { id: 554, category: "Next.js", subcategory: "App Router", level: "intermediate", q: "loading.tsx và Suspense trong Next.js App Router?", a: "`loading.tsx` tự động tạo Suspense boundary bọc page hoặc layout, hiển thị loading UI ngay lập tức khi navigate. Streaming: Next.js stream HTML từng phần, user thấy nội dung nhanh hơn thay vì đợi toàn trang. Instant loading states không cần manually thêm Suspense và fallback UI." },
  { id: 555, category: "Next.js", subcategory: "App Router", level: "intermediate", q: "error.tsx và not-found.tsx trong Next.js hoạt động như thế nào?", a: "`error.tsx` phải là Client Component, nhận `error` và `reset` props, hiển thị khi có lỗi trong segment. `not-found.tsx` hiển thị khi gọi `notFound()` từ server component hoặc khi URL không match route nào. Global error.tsx ở root app/ bắt lỗi kể cả trong root layout." },
  { id: 556, category: "Next.js", subcategory: "App Router", level: "intermediate", q: "Route Groups trong Next.js là gì?", a: "Route Groups dùng ngoặc đơn `(groupName)` để tổ chức routes mà không ảnh hưởng URL. Ví dụ: `(auth)/login` và `(auth)/register` share cùng layout auth nhưng URL vẫn là `/login` và `/register`. Useful để: apply layout cho subset of routes, organize large codebases theo features." },
  { id: 557, category: "Next.js", subcategory: "App Router", level: "intermediate", q: "Dynamic routes và catch-all routes trong Next.js App Router?", a: "Dynamic: `app/blog/[slug]/page.tsx` match `/blog/anything`, access qua `params.slug`. Catch-all: `app/[...slug]` match `/a/b/c`, params là array. Optional catch-all: `app/[[...slug]]` match kể cả root route. Với multiple params: `app/[category]/[id]`. Type params với TypeScript trong PageProps." },
  { id: 558, category: "Next.js", subcategory: "App Router", level: "advanced", q: "Parallel Routes và Intercepting Routes trong Next.js là gì?", a: "Parallel Routes dùng `@slot` convention để render nhiều pages cùng lúc trong cùng layout (ví dụ modal + page). Intercepting Routes (`(.)path`, `(..)path`) cho phép intercept route và hiển thị trong context hiện tại (như Instagram photo modal). Phù hợp cho modal workflows phức tạp không mất URL sharability." },
  { id: 559, category: "Next.js", subcategory: "App Router", level: "beginner", q: "Metadata trong Next.js App Router được định nghĩa như thế nào?", a: "Export `metadata` object hoặc `generateMetadata` function từ page.tsx hoặc layout.tsx. Tự động merge metadata từ parent layouts. `export const metadata = { title: 'Page Title', description: '...' }`. `generateMetadata` là async function nhận params để tạo dynamic metadata cho dynamic routes. Thay thế cho next/head." },
  { id: 560, category: "Next.js", subcategory: "App Router", level: "intermediate", q: "generateStaticParams trong Next.js App Router dùng để làm gì?", a: "generateStaticParams export từ dynamic route page để pre-generate static paths tại build time, tương đương getStaticPaths trong Pages Router. `export async function generateStaticParams() { return posts.map(p => ({ slug: p.slug })) }`. Kết hợp với Static Generation để tạo static pages cho mọi possible value." },

  // === Next.js - Server/Client Components (561-570) ===
  { id: 561, category: "Next.js", subcategory: "Server/Client Components", level: "intermediate", q: "React Server Components là gì?", a: "Server Components render hoàn toàn trên server, HTML được gửi xuống client. Không có JavaScript bundle gửi xuống cho server components. Có thể trực tiếp access database, file system, server-only APIs. Không hỗ trợ: state, effects, event handlers, browser APIs. Mặc định trong App Router, giúp giảm bundle size và cải thiện performance." },
  { id: 562, category: "Next.js", subcategory: "Server/Client Components", level: "beginner", q: "'use client' directive trong Next.js dùng khi nào?", a: "`'use client'` đặt ở đầu file để đánh dấu component là Client Component. Cần thiết khi component dùng: useState, useEffect, event handlers (onClick), browser APIs (window, localStorage), third-party client libraries. Mặc định không cần directive - component là Server Component. Đặt boundary tại component cần interactivity, không cần wrap toàn app." },
  { id: 563, category: "Next.js", subcategory: "Server/Client Components", level: "intermediate", q: "Server Component có thể import Client Component không và ngược lại?", a: "Server Component có thể import và render Client Component - đây là hướng dependency bình thường. Ngược lại: Client Component KHÔNG thể import Server Component vì server component sẽ bị client-ize. Nhưng Server Component có thể truyền Server Component làm children/props cho Client Component (pattern được phép)." },
  { id: 564, category: "Next.js", subcategory: "Server/Client Components", level: "intermediate", q: "Khi nào nên dùng Server Component, khi nào dùng Client Component?", a: "Server Component khi cần: data fetching, access backend resources, keep sensitive info (API keys), reduce client bundle. Client Component khi cần: onClick, onChange event handlers, useState/useEffect, browser APIs, real-time updates, custom hooks. Default là Server, chỉ dùng 'use client' khi thực sự cần interactivity." },
  { id: 565, category: "Next.js", subcategory: "Server/Client Components", level: "advanced", q: "Server Component props phải tuân theo quy tắc gì?", a: "Props từ Server sang Client Component phải serializable (có thể convert to JSON): strings, numbers, booleans, arrays, plain objects. Không thể truyền: functions, class instances, Symbols, Date objects (trực tiếp), React elements cũng có hạn chế. JSX làm children có thể pass. Cần serialize Date thành string trước khi pass." },
  { id: 566, category: "Next.js", subcategory: "Server/Client Components", level: "intermediate", q: "Context API có hoạt động với Server Components không?", a: "Context API không hoạt động trong Server Components vì context phụ thuộc React runtime trên client. Chỉ Client Components trong component tree mới có thể dùng Context. Để share data trong Server Components, truyền qua props hoặc dùng Next.js built-ins như hàm await cookies() và await headers() (async kể từ Next.js 15+). Tạo Context Provider là Client Component và wrap children." },
  { id: 567, category: "Next.js", subcategory: "Server/Client Components", level: "advanced", q: "Taint API trong React và Next.js là gì?", a: "React Taint API (experimental) cho phép đánh dấu objects và values là sensitive để ngăn vô tình pass xuống Client Components. `taintObjectReference(message, object)` và `taintUniqueValue(message, object, value)`. Ví dụ: taint user password, API keys. Giúp prevent server-side secrets leak xuống client bundle." },
  { id: 568, category: "Next.js", subcategory: "Server/Client Components", level: "intermediate", q: "Third-party libraries và Server Components có vấn đề gì?", a: "Nhiều npm packages cũ dùng browser APIs hay React client features mà không có 'use client'. Giải pháp: tạo wrapper Client Component import library đó, thêm 'use client' ở wrapper. Next.js có boundary tự động cho packages với 'use client' trong package.json exports. Kiểm tra compatibility trước khi dùng library mới." },
  { id: 569, category: "Next.js", subcategory: "Server/Client Components", level: "beginner", q: "Server-only và client-only packages trong Next.js là gì?", a: "`server-only` package throw error tại build time nếu vô tình import server code vào client bundle. `client-only` throw nếu import client code trên server. Dùng: `import 'server-only'` đầu file chứa database connections, API keys. Giúp catch mistakes sớm thay vì runtime errors hay security issues." },
  { id: 570, category: "Next.js", subcategory: "Server/Client Components", level: "advanced", q: "React Server Components streaming và progressive rendering là gì?", a: "Next.js stream HTML theo từng phần thay vì đợi toàn page ready. Server components có thể wrap trong Suspense, phần xung quanh stream trước, khi data ready phần trong Suspense stream tiếp. User thấy content nhanh hơn. TTFB tốt hơn. Cần design components để render độc lập và không block lẫn nhau." },

  // === Next.js - Rendering (571-580) ===
  { id: 571, category: "Next.js", subcategory: "Rendering", level: "beginner", q: "SSR (Server-Side Rendering) trong Next.js là gì?", a: "SSR render HTML trên server cho mỗi request, trả về fully-rendered HTML cho browser. Tốt cho: SEO, trang có data thay đổi thường xuyên theo user, first paint nhanh. Trong App Router: mặc định Server Components là SSR. Pages Router: dùng `getServerSideProps`. Nhược điểm: server phải xử lý nhiều, TTFB cao hơn SSG." },
  { id: 572, category: "Next.js", subcategory: "Rendering", level: "beginner", q: "SSG (Static Site Generation) trong Next.js là gì?", a: "SSG tạo HTML tại build time, serve static files từ CDN. Cực kỳ nhanh, không cần server processing mỗi request. Phù hợp cho: blog, documentation, marketing pages, data ít thay đổi. Pages Router: không có getServerSideProps. App Router: dùng `export const dynamic = 'force-static'`. Nhược điểm: phải rebuild để cập nhật content." },
  { id: 573, category: "Next.js", subcategory: "Rendering", level: "intermediate", q: "ISR (Incremental Static Regeneration) là gì?", a: "ISR kết hợp SSG và SSR: trang được generate tĩnh, nhưng sau `revalidate` seconds có thể regenerate lại. User đầu tiên sau revalidate nhận stale content, trigger background regeneration. User sau nhận fresh content. Pages Router: `return { revalidate: 60 }` trong getStaticProps. App Router: `export const revalidate = 60` hoặc `fetch(url, { next: { revalidate: 60 } })`." },
  { id: 574, category: "Next.js", subcategory: "Rendering", level: "intermediate", q: "On-demand revalidation trong Next.js là gì?", a: "On-demand revalidation cho phép invalidate cache và regenerate pages ngay lập tức thay vì đợi timeout. Pages Router: `res.revalidate('/path')` trong API route. App Router: `revalidatePath('/path')` hoặc `revalidateTag('posts')` trong Server Action hoặc Route Handler. Phù hợp khi CMS webhook trigger cần update content ngay." },
  { id: 575, category: "Next.js", subcategory: "Rendering", level: "intermediate", q: "fetch cache trong Next.js App Router hoạt động như thế nào?", a: "Next.js extend native fetch với caching: `fetch(url)` mặc định `no-store` từ Next.js 15+ (trước đó cache), `{ cache: 'force-cache' }` để opt-in cache, `{ next: { revalidate: 60 } }` revalidate sau 60 giây. `{ next: { tags: ['posts'] } }` tag để invalidate theo tag. Data cache tách biệt với Full Route Cache." },
  { id: 576, category: "Next.js", subcategory: "Rendering", level: "advanced", q: "Next.js có những loại cache nào?", a: "Next.js có 4 loại cache: (1) Request Memoization: dedup fetch calls trong cùng request tree. (2) Data Cache: persist fetch results giữa requests và deployments. (3) Full Route Cache: cache rendered HTML và RSC payload trên server. (4) Router Cache: client-side cache của RSC payload, prefetch routes." },
  { id: 577, category: "Next.js", subcategory: "Rendering", level: "intermediate", q: "Sự khác biệt giữa dynamic và static rendering trong App Router?", a: "Static rendering: render lúc build time, cache và serve từ CDN. Dynamic rendering: render mỗi request, không cache. Tự động dynamic khi dùng: await cookies(), await headers(), searchParams, hay fetch với cache: 'no-store'. Explicit: `export const dynamic = 'force-dynamic'` hoặc `'force-static'`. Opt-in static càng nhiều càng tốt cho performance." },
  { id: 578, category: "Next.js", subcategory: "Rendering", level: "beginner", q: "getStaticProps và getServerSideProps khác nhau như thế nào?", a: "getStaticProps chạy tại build time, data embed vào static HTML, tốc độ cực nhanh, tốt cho data ít thay đổi. getServerSideProps chạy mỗi request, data luôn fresh, nhưng chậm hơn vì phải đợi server. Cả hai chỉ có trong Pages Router. App Router thay thế bằng Server Components với fetch cache options." },
  { id: 579, category: "Next.js", subcategory: "Rendering", level: "intermediate", q: "Streaming SSR trong Next.js hoạt động như thế nào?", a: "Streaming SSR gửi HTML từng phần xuống browser ngay khi ready thay vì đợi toàn trang. Dùng HTTP chunked transfer encoding. Kết hợp với Suspense: phần ngoài Suspense stream trước, phần trong stream khi data ready. Giảm Time to First Byte và First Contentful Paint. Enabled mặc định trong App Router." },
  { id: 580, category: "Next.js", subcategory: "Rendering", level: "advanced", q: "Partial Prerendering (PPR) trong Next.js là gì?", a: "Partial Prerendering (experimental, Next.js 14) cho phép combine static shell và dynamic holes trong cùng một page. Static parts được prerender và cached, dynamic parts (trong Suspense) được stream khi request. User nhận static shell ngay lập tức, dynamic content load sau. Tốt nhất của SSG và SSR trong một trang." },

  // === Next.js - API & Server Actions (581-590) ===
  { id: 581, category: "Next.js", subcategory: "API & Server Actions", level: "beginner", q: "Route Handlers (API Routes) trong Next.js App Router là gì?", a: "Route Handlers là `route.ts` file trong app/ directory xử lý HTTP requests. Export named functions theo HTTP method: `export async function GET(request) {}`, `export async function POST(request) {}`. Dùng Web APIs chuẩn (Request, Response). Thay thế cho `pages/api/` trong Pages Router." },
  { id: 582, category: "Next.js", subcategory: "API & Server Actions", level: "intermediate", q: "Server Actions trong Next.js là gì?", a: "Server Actions là async functions chạy trên server, được gọi từ Client Components hoặc forms. Khai báo với `'use server'` directive. Cho phép mutate data trực tiếp từ component mà không cần tạo API endpoint. Tự động xử lý serialization, error handling. Tốt cho: form submission, button actions, mutations." },
  { id: 583, category: "Next.js", subcategory: "API & Server Actions", level: "intermediate", q: "Cách sử dụng Server Actions với HTML forms?", a: "Gán Server Action vào form action attribute: `<form action={createPost}>`. Form submit tự động gọi Server Action với FormData. Không cần JavaScript client-side (progressive enhancement). Trong action: `const title = formData.get('title')`. Kết hợp với useFormState (React 18) hoặc useActionState (React 19) để track state." },
  { id: 584, category: "Next.js", subcategory: "API & Server Actions", level: "intermediate", q: "Revalidation sau mutation trong Server Actions?", a: "Sau khi mutate data trong Server Action, cần revalidate cache để UI cập nhật: `revalidatePath('/posts')` invalidate cached route, `revalidateTag('posts')` invalidate theo tag. `redirect('/path')` để điều hướng sau action thành công." },
  { id: 585, category: "Next.js", subcategory: "API & Server Actions", level: "intermediate", q: "Error handling trong Server Actions như thế nào?", a: "Server Actions có thể throw errors sẽ được catch bởi nearest error.tsx. Với useFormState/useActionState, return error object thay vì throw: `return { error: 'Invalid input' }`. Dùng try/catch trong action để handle expected errors (validation, not found) và return user-friendly error states." },
  { id: 586, category: "Next.js", subcategory: "API & Server Actions", level: "advanced", q: "Security considerations khi dùng Server Actions?", a: "Server Actions tự động có CSRF protection từ Next.js. Tuy nhiên vẫn cần: validate và sanitize inputs (không trust FormData), authenticate user trong action (check session), authorize permissions, rate limiting. Server Actions là public API endpoints dù không có URL, nên treat như REST endpoints về security." },
  { id: 587, category: "Next.js", subcategory: "API & Server Actions", level: "intermediate", q: "Middleware trong Next.js App Router là gì?", a: "Middleware là `middleware.ts` ở root, chạy trên Edge runtime trước mọi request. Dùng để: authentication/authorization, redirect, rewrite URL, add/modify headers, A/B testing. Return NextResponse để điều khiển response. Dùng `matcher` config để chỉ định routes áp dụng. Nhẹ và nhanh vì Edge runtime." },
  { id: 588, category: "Next.js", subcategory: "API & Server Actions", level: "intermediate", q: "Cookies và Headers trong Next.js Server Components và Actions?", a: "Import từ next/headers, cả hai đều là async kể từ Next.js 15+: `const cookieStore = await cookies()` và `const headersList = await headers()`. Đọc cookie: `cookieStore.get('session')`, `cookieStore.set('session', value)`. Đọc header: `headersList.get('user-agent')`. Trong Server Components: read-only. Trong Server Actions và Route Handlers: có thể read và write." },
  { id: 589, category: "Next.js", subcategory: "API & Server Actions", level: "intermediate", q: "Optimistic updates với Server Actions và useOptimistic?", a: "useOptimistic (React 19) kết hợp với Server Actions: cập nhật UI ngay trước khi action hoàn thành, rollback nếu fail. `const [optimistic, addOptimistic] = useOptimistic(data, updateFn)`. Trong action handler: `addOptimistic(newItem)` trước `await serverAction()`. Tạo snappy UX dù có network latency." },
  { id: 590, category: "Next.js", subcategory: "API & Server Actions", level: "advanced", q: "Edge Runtime vs Node.js Runtime trong Next.js là gì?", a: "Node.js Runtime: đầy đủ Node.js APIs, có thể dùng npm packages, phù hợp cho heavy computation. Edge Runtime: V8 engine không có Node.js APIs, giới hạn package support, nhưng cực kỳ nhanh (chạy gần user), cold start gần 0. Middleware mặc định Edge. Route Handlers có thể chọn: `export const runtime = 'edge'` hoặc `'nodejs'`." },

  // === Next.js - Optimization (591-600) ===
  { id: 591, category: "Next.js", subcategory: "Optimization", level: "intermediate", q: "next/image component mang lại lợi ích gì?", a: "next/image tự động: resize và optimize images theo viewport, serve WebP/AVIF modern formats, lazy load mặc định, prevent Cumulative Layout Shift (CLS) với width/height hoặc fill. Cần cung cấp width và height hoặc fill prop. Cấu hình allowed domains trong next.config. Tích hợp CDN support sẵn." },
  { id: 592, category: "Next.js", subcategory: "Optimization", level: "intermediate", q: "next/font trong Next.js hoạt động như thế nào?", a: "next/font tự động: download Google Fonts tại build time (không request runtime đến Google), host fonts trên cùng server, zero layout shift với automatic size adjustment, privacy tốt hơn. Dùng: `import { Inter } from 'next/font/google'; const inter = Inter({ subsets: ['latin'] })`. Apply qua className. Hỗ trợ local fonts qua next/font/local." },
  { id: 593, category: "Next.js", subcategory: "Optimization", level: "intermediate", q: "Link prefetching trong Next.js là gì và cách control?", a: "Next.js tự động prefetch routes khi Link component vào viewport (production). Tải JS chunk và data cho route đó trước khi user click, tạo instant navigation. Disable: `<Link prefetch={false}>`. App Router prefetch RSC payload. Control cụ thể: prefetch attribute hoặc router.prefetch(). Giúp navigation cảm giác instantaneous." },
  { id: 594, category: "Next.js", subcategory: "Optimization", level: "intermediate", q: "next/script component và loading strategies là gì?", a: "next/script tối ưu loading third-party scripts. Strategies: `beforeInteractive` (trước hydration, cho critical scripts), `afterInteractive` (sau hydration, default), `lazyOnload` (idle time), `worker` (web worker với Partytown). Tránh dùng thẻ script thông thường trong App Router, dùng next/script thay thế." },
  { id: 595, category: "Next.js", subcategory: "Optimization", level: "advanced", q: "Bundle analyzer trong Next.js được dùng như thế nào?", a: "Dùng @next/bundle-analyzer để visualize bundle size. Cấu hình trong next.config.js với withBundleAnalyzer wrapper. Chạy `ANALYZE=true npm run build` để tạo report HTML. Giúp identify: large dependencies, duplicate code, unnecessary imports. Sau đó tối ưu: dynamic imports, tree-shaking, replace heavy libraries." },
  { id: 596, category: "Next.js", subcategory: "Optimization", level: "intermediate", q: "Middleware proxy pattern trong Next.js như thế nào?", a: "Middleware có thể rewrite requests đến API khác: `NextResponse.rewrite(new URL('/api/proxy', request.url))`. Hoặc trong next.config.js dùng `rewrites` array để proxy: `{ source: '/api/:path*', destination: 'https://backend.com/:path*' }`. Hữu ích để: hide API endpoints, implement BFF (Backend For Frontend), avoid CORS issues." },
  { id: 597, category: "Next.js", subcategory: "Optimization", level: "intermediate", q: "Core Web Vitals và Next.js tối ưu chúng như thế nào?", a: "Next.js tối ưu: LCP (Largest Contentful Paint) qua image optimization, priority images; CLS (Cumulative Layout Shift) qua next/image với dimensions, next/font với size-adjust; FID/INP (Interaction to Next Paint) qua code splitting, lazy loading, Concurrent Mode. `next/analytics` báo cáo Core Web Vitals production." },
  { id: 598, category: "Next.js", subcategory: "Optimization", level: "advanced", q: "Turbopack là gì và lợi ích của nó trong Next.js?", a: "Turbopack là Rust-based bundler thay thế Webpack trong Next.js (stable cho dev trong Next.js 15). Nhanh hơn đáng kể cho local development: incremental builds, chỉ compile những gì thay đổi. HMR (Hot Module Replacement) cực nhanh ngay cả với large codebases. Production bundling vẫn đang trong development." },
  { id: 599, category: "Next.js", subcategory: "Optimization", level: "intermediate", q: "Environment variables trong Next.js được xử lý như thế nào?", a: "`.env.local` cho local development (git-ignored). `.env.production`, `.env.development` cho môi trường cụ thể. `NEXT_PUBLIC_` prefix expose biến xuống client bundle - KHÔNG đặt secrets với prefix này. Không có prefix: chỉ server-side. Trong App Router: server components đọc trực tiếp `process.env.VAR`. Client: chỉ NEXT_PUBLIC_ vars." },
  { id: 600, category: "Next.js", subcategory: "Optimization", level: "advanced", q: "Internationalization (i18n) trong Next.js được implement như thế nào?", a: "App Router: không có built-in i18n, dùng middleware để detect locale từ Accept-Language header, redirect đến locale-prefixed routes `/en/about`. Dùng libraries: next-intl, next-i18next. Tạo `[locale]` dynamic segment, load messages tương ứng. Pages Router có built-in i18n config với `i18n: { locales, defaultLocale }` trong next.config." },
]
